package com.friend.ios.limitless

import org.json.JSONObject
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertNull
import org.junit.Test
import java.io.File

/**
 * Verifies the Kotlin port against the golden fixtures generated by the Dart side
 * (`app/test/unit/limitless_golden_test.dart` → `app/test/fixtures/limitless_golden/`).
 * Both implementations must produce byte-identical results for every fixture.
 */
class LimitlessProtocolTest {

    private fun fixturesDir(): File {
        var dir: File? = File(System.getProperty("user.dir") ?: "").absoluteFile
        while (dir != null) {
            val direct = File(dir, "test/fixtures/limitless_golden")
            if (direct.isDirectory) return direct
            val viaApp = File(dir, "app/test/fixtures/limitless_golden")
            if (viaApp.isDirectory) return viaApp
            dir = dir.parentFile
        }
        throw AssertionError("Could not locate app/test/fixtures/limitless_golden above ${System.getProperty("user.dir")}")
    }

    private fun loadFixture(name: String): JSONObject {
        val file = File(fixturesDir(), name)
        if (!file.isFile) {
            throw AssertionError("Missing fixture $name — run `cd app && flutter test test/unit/limitless_golden_test.dart` to generate it")
        }
        return JSONObject(file.readText())
    }

    private fun hexToBytes(hex: String): ByteArray =
        ByteArray(hex.length / 2) { ((hex.substring(it * 2, it * 2 + 2)).toInt(16)).toByte() }

    private fun bytesToHex(bytes: ByteArray): String =
        bytes.joinToString("") { "%02x".format(it.toInt() and 0xFF) }

    /** Mirrors the fragment-reassembly loop in [LimitlessFlashDrainEngine.processPacket]. */
    private fun drainPages(packets: List<ByteArray>): List<LimitlessProtocol.FlashPage> {
        val fragmentBuffer = mutableMapOf<Int, MutableMap<Int, ByteArray>>()
        val pages = mutableListOf<LimitlessProtocol.FlashPage>()
        for (data in packets) {
            val packet = LimitlessProtocol.parseBlePacket(data) ?: continue
            fragmentBuffer.getOrPut(packet.index) { mutableMapOf() }[packet.seq] = packet.payload
            val fragments = fragmentBuffer[packet.index] ?: continue
            if (fragments.size != packet.numFrags) continue

            var totalSize = 0
            for (i in 0 until packet.numFrags) {
                totalSize += fragments[i]?.size ?: 0
            }
            val complete = ByteArray(totalSize)
            var offset = 0
            for (i in 0 until packet.numFrags) {
                val fragment = fragments[i] ?: continue
                fragment.copyInto(complete, offset)
                offset += fragment.size
            }
            fragmentBuffer.remove(packet.index)
            pages.addAll(LimitlessProtocol.parsePendantMessage(complete))
        }
        return pages
    }

    private fun assertFixture(fileName: String) {
        val fixture = loadFixture(fileName)
        val packetsJson = fixture.getJSONArray("packets")
        val packets = (0 until packetsJson.length()).map { hexToBytes(packetsJson.getString(it)) }

        val expectedPages = fixture.getJSONArray("expectedPages")
        val pages = drainPages(packets)
        assertEquals("$fileName: page count", expectedPages.length(), pages.size)
        for (i in 0 until expectedPages.length()) {
            val expected = expectedPages.getJSONObject(i)
            val page = pages[i]
            assertEquals("$fileName pages[$i].index", expected.getInt("index"), page.index)
            assertEquals("$fileName pages[$i].session", expected.getInt("session"), page.session)
            assertEquals("$fileName pages[$i].timestampMs", expected.getLong("timestampMs"), page.timestampMs)
            val frames = expected.getJSONArray("frames")
            assertEquals("$fileName pages[$i]: frame count", frames.length(), page.opusFrames.size)
            for (j in 0 until frames.length()) {
                assertEquals("$fileName pages[$i].frames[$j]", frames.getString(j), bytesToHex(page.opusFrames[j]))
            }
        }

        val actualState = packets.asSequence().mapNotNull { LimitlessProtocol.parseDeviceStatus(it) }.firstOrNull()
        if (fixture.isNull("expectedStorageState")) {
            assertNull("$fileName: expected no device-status parse", actualState)
        } else {
            val expected = fixture.getJSONObject("expectedStorageState")
            assertNotNull("$fileName: expected a device-status parse", actualState)
            assertEquals("$fileName oldest", expected.getInt("oldest_flash_page"), actualState!!.oldestFlashPage)
            assertEquals("$fileName newest", expected.getInt("newest_flash_page"), actualState.newestFlashPage)
            assertEquals("$fileName session", expected.getInt("current_storage_session"), actualState.currentStorageSession)
            assertEquals("$fileName free", expected.getInt("free_capture_pages"), actualState.freeCapturePages)
            assertEquals("$fileName total", expected.getInt("total_capture_pages"), actualState.totalCapturePages)
        }
    }

    @Test
    fun singleFragmentAudioPage() = assertFixture("single_fragment_audio_page.json")

    @Test
    fun threeFragmentsOutOfOrder() = assertFixture("three_fragments_out_of_order.json")

    @Test
    fun diagnosticPageNoAudio() = assertFixture("diagnostic_page_no_audio.json")

    @Test
    fun nestedAudioContainers() = assertFixture("nested_audio_containers.json")

    @Test
    fun invalidTocInterleaved() = assertFixture("invalid_toc_interleaved.json")

    @Test
    fun deviceStatus() = assertFixture("device_status.json")

    @Test
    fun truncatedTrailingField() = assertFixture("truncated_trailing_field.json")

    @Test
    fun audioPageZeroFrames() = assertFixture("audio_page_zero_frames.json")

    @Test(timeout = 10_000)
    fun overflowVarintLength() = assertFixture("overflow_varint_length.json")

    @Test(timeout = 10_000)
    fun fixed64FieldsPage() = assertFixture("fixed64_fields_page.json")

    @Test(timeout = 10_000)
    fun unknownWiretypePage() = assertFixture("unknown_wiretype_page.json")

    @Test
    fun encoderVectors() {
        val fixture = loadFixture("encoders.json")
        val vectors = fixture.getJSONArray("vectors")
        for (i in 0 until vectors.length()) {
            val vector = vectors.getJSONObject(i)
            val name = vector.getString("name")
            val messageIndex = vector.getInt("messageIndex")
            val requestId = vector.getLong("requestId")
            val actual = when {
                name == "msg6_set_current_time" ->
                    LimitlessProtocol.encodeSetCurrentTime(messageIndex, requestId, vector.getLong("timestampMs"))
                name == "msg7_ack_12345" ->
                    LimitlessProtocol.encodeAcknowledgeProcessedData(messageIndex, requestId, vector.getInt("upToIndex"))
                name == "msg21_get_device_status" ->
                    LimitlessProtocol.encodeGetDeviceStatus(messageIndex, requestId)
                name.startsWith("msg8_") ->
                    LimitlessProtocol.encodeDownloadFlashPages(
                        messageIndex,
                        requestId,
                        vector.getBoolean("batchMode"),
                        vector.getBoolean("realTime"),
                    )
                else -> throw AssertionError("Unknown encoder vector $name — update LimitlessProtocolTest")
            }
            assertEquals("encoder $name", vector.getString("hex"), bytesToHex(actual))
        }
    }
}
